// Verify the postinstall-generated assets match the committed hashes in
// vendor-hashes.json, so the shipped bundle's generated bytes are accounted
// for by public source.
//
// ENFORCING (ENFORCE = true) since 2026-07-05: regeneration was proven
// byte-identical locally (two runs, identical sha256) and across
// environments (CI on the pinned lockfile produces the same hashes).
// A mismatch now fails pnpm check. After a deliberate @twemoji/svg,
// harfbuzzjs, or svgo bump, regenerate with `node scripts/vendor-twemoji.mjs`
// and update vendor-hashes.json in the same commit.

import { readFileSync } from 'node:fs';
import { createHash } from 'node:crypto';
import { resolve, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';

const ENFORCE = true;

const repoRoot = resolve(dirname(fileURLToPath(import.meta.url)), '..');
const manifest = JSON.parse(readFileSync(resolve(repoRoot, 'vendor-hashes.json'), 'utf8'));
const entries = Object.entries(manifest).filter(([k]) => !k.startsWith('_'));

let mismatches = 0;
for (const [rel, expected] of entries) {
  let actual;
  try {
    actual = createHash('sha256').update(readFileSync(resolve(repoRoot, rel))).digest('hex');
  } catch (e) {
    console.warn(`[vendor-hashes] missing ${rel} (run pnpm install): ${e?.message || e}`);
    mismatches++;
    continue;
  }
  if (actual !== expected) {
    console.warn(`[vendor-hashes] MISMATCH ${rel}\n  expected ${expected}\n  actual   ${actual}`);
    mismatches++;
  }
}

if (mismatches === 0) {
  console.log(`[vendor-hashes] ok — ${entries.length} generated assets match vendor-hashes.json`);
} else if (ENFORCE) {
  console.error(`[vendor-hashes] ${mismatches} mismatch(es); failing (ENFORCE=true)`);
  process.exit(1);
} else {
  console.warn(`[vendor-hashes] ${mismatches} mismatch(es) — warn-only. If a dependency was bumped intentionally, regenerate and update vendor-hashes.json.`);
}
